# Sum of Two Integers — O(1) space, O(32) iterations max
# KEY INSIGHT: XOR = sum without carry, AND<<1 = carry

def getSum(a, b):
    mask = 0xFFFFFFFF  # 32-bit mask for Python

    while b & mask:
        carry = (a & b) << 1
        a = a ^ b
        b = carry

    # Handle Python's arbitrary precision for negative results
    if b == 0:
        return a & mask if a > 0x7FFFFFFF else a
    else:
        return b  # b has the final carry (non-masked)

